// Extract topic and execution ID from webhook
const body = $input.item.json.body || $input.item.json;
const topic = body.topic;
const executionId = body.executionId;
const options = body.options || {};

if (!topic || !executionId) {
  throw new Error('Missing required fields: topic and executionId');
}

return {
  json: {
    topic,
    executionId,
    options,
    stage: 'query_expansion',
    timestamp: new Date().toISOString()
  }
};

// Parse LLM response and prepare for paper retrieval
const message = $input.item.json.message;
const content = message?.content || message || '';
let queries;

try {
  // Try to parse as JSON
  queries = JSON.parse(content);
  if (!Array.isArray(queries)) {
    queries = [content];
  }
} catch (e) {
  // Fallback to original topic if parsing fails
  queries = [$input.item.json.topic || 'machine learning'];
}

// Ensure we have at least one query
if (queries.length === 0) {
  queries = [$input.item.json.topic || 'machine learning'];
}

return {
  json: {
    topic: $input.item.json.topic,
    executionId: $input.item.json.executionId,
    queries,
    stage: 'retrieval'
  }
};

// Filter and normalize paper data
const response = $input.item.json;
const papers = response.data || [];
const executionId = $input.first().json.executionId;
const topic = $input.first().json.topic;

// Filter English papers and extract metadata
const filteredPapers = papers
  .filter(paper => paper.title && paper.abstract)
  .map(paper => ({
    externalId: paper.paperId || `paper-${Date.now()}-${Math.random()}`,
    title: paper.title,
    authors: (paper.authors || []).map(a => ({ name: a.name || 'Unknown' })),
    abstract: paper.abstract || '',
    publicationYear: paper.year || new Date().getFullYear(),
    citationCount: paper.citationCount || 0,
    venue: paper.venue || 'Unknown',
    url: paper.url || '',
    language: 'en'
  }));

return {
  json: {
    executionId,
    topic,
    papers: filteredPapers,
    stage: 'validation',
    paperCount: filteredPapers.length
  }
};

// Apply quality scores and filter
const papers = $input.first().json.papers;
const message = $input.item.json.message;
const content = message?.content || message || '';
let scores;

try {
  scores = JSON.parse(content);
  if (!Array.isArray(scores)) {
    scores = [];
  }
} catch (e) {
  // Fallback: assign default scores
  scores = papers.map((p, i) => ({ index: i, score: 7.0 }));
}

// Apply scores and filter (threshold: 6.0)
const validatedPapers = papers
  .map((paper, index) => {
    const scoreData = scores.find(s => s.index === index) || { score: 7.0 };
    return { ...paper, qualityScore: scoreData.score };
  })
  .filter(paper => paper.qualityScore >= 6.0)
  .sort((a, b) => b.qualityScore - a.qualityScore);

return {
  json: {
    executionId: $input.first().json.executionId,
    topic: $input.first().json.topic,
    papers: validatedPapers,
    stage: 'evaluation'
  }
};

parameters.text:
=Analyze these academic papers for relevance to the topic and extract key themes.

Topic: {{ $json.topic }}

Papers:
{{ JSON.stringify($json.papers.slice(0, 15), null, 2) }}

For each paper:
1. Assign relevance score (0-10)
2. Identify 2-3 key themes

Also identify 3-5 major themes across all papers.

Return JSON: {"papers": [{"index": 0, "relevance": 9.0, "themes": ["theme1", "theme2"]}], "majorThemes": ["theme1", "theme2", "theme3"]}

parameters.functionCode:
// Apply relevance scores and select top papers
const papers = $input.first().json.papers;
const message = $input.item.json.message;
const content = message?.content || message || '';
let evaluation;

try {
  evaluation = JSON.parse(content);
  if (!evaluation.papers || !Array.isArray(evaluation.papers)) {
    throw new Error('Invalid evaluation format');
  }
} catch (e) {
  evaluation = {
    papers: papers.map((p, i) => ({ index: i, relevance: 8.0, themes: ['general'] })),
    majorThemes: ['general research']
  };
}

// Apply relevance scores
const evaluatedPapers = papers
  .map((paper, index) => {
    const evalData = evaluation.papers.find(e => e.index === index) || { relevance: 8.0, themes: [] };
    return {
      ...paper,
      relevanceScore: evalData.relevance,
      themes: evalData.themes
    };
  })
  .sort((a, b) => b.relevanceScore - a.relevanceScore)
  .slice(0, 15); // Top 15 papers

return {
  json: {
    executionId: $input.first().json.executionId,
    topic: $input.first().json.topic,
    papers: evaluatedPapers,
    majorThemes: evaluation.majorThemes || ['general research'],
    stage: 'synthesis'
  }
};

parameters.text:
=Create a comprehensive literature survey on: {{ $json.topic }}

Using these papers:
{{ JSON.stringify($json.papers, null, 2) }}

Major themes: {{ JSON.stringify($json.majorThemes) }}

Structure:
1. Introduction (context, scope, importance)
2. Thematic sections (one per major theme, group relevant papers)
3. Conclusion (synthesis, gaps, future directions)

Format citations as [Author et al., Year].
Return JSON: {"introduction": "...", "sections": [{"title": "...", "content": "...", "paperIds": [...]}], "conclusion": "..."}

parameters.functionCode:
// Format final survey and prepare for storage
const message = $input.item.json.message;
const content = message?.content || message || '';
let surveyContent;

try {
  surveyContent = JSON.parse(content);
  if (!surveyContent.introduction || !surveyContent.sections || !surveyContent.conclusion) {
    throw new Error('Invalid survey format');
  }
} catch (e) {
  surveyContent = {
    introduction: 'Survey generation in progress...',
    sections: [],
    conclusion: 'To be completed...'
  };
}

// Build references
const papers = $input.first().json.papers;
const references = papers.map(paper => ({
  authors: paper.authors.map(a => a.name),
  year: paper.publicationYear,
  title: paper.title,
  venue: paper.venue,
  url: paper.url
}));

// Calculate metadata
const wordCount = JSON.stringify(surveyContent).split(/\s+/).length;

return {
  json: {
    executionId: $input.first().json.executionId,
    topic: $input.first().json.topic,
    content: {
      ...surveyContent,
      references
    },
    metadata: {
      paperCount: papers.length,
      wordCount,
      generatedAt: new Date().toISOString(),
      themes: $input.first().json.majorThemes
    },
    stage: 'complete'
  }
};
